  describe "metadata_author_meta" do
    test "Extract author from <meta name='author'> tag" do
      {:ok, result} = HtmlToMarkdownRs.convert("<html><head><title>Page</title><meta name=\"author\" content=\"Jane Doe\"></head><body><p>Content</p></body></html>")
      assert result.content != ""
      assert String.trim(result.metadata.document.author) == "Jane Doe"
    end
  end

  describe "metadata_canonical_url" do
    test "Extract canonical URL from <link rel='canonical'> tag" do
      {:ok, result} = HtmlToMarkdownRs.convert("<html><head><title>Page</title><link rel=\"canonical\" href=\"https://example.com/canonical-page\"></head><body><p>Content</p></body></html>")
      assert result.content != ""
      assert String.trim(result.metadata.document.canonical_url) == "https://example.com/canonical-page"
    end
  end

